code = """import pandas as pd
import json

# Load the clinical data for alive BRCA patients (JSON string from previous execute_python call)
alive_brca_patients = pd.read_json(locals()['var_function-call-9178491985777040403'])

# Load CDH1 mutations from the file path (result of query_db call)
with open(locals()['var_function-call-14184087652938889272'], 'r') as f:
    cdh1_mutations = pd.read_json(f)

# Merge the dataframes to link mutations to patient histological types
merged_data = pd.merge(alive_brca_patients, cdh1_mutations, on='ParticipantBarcode', how='left')

# Group by histological_type and count total patients and patients with CDH1 mutations
histological_type_summary = merged_data.groupby('histological_type').agg(
    total_patients=('ParticipantBarcode', 'nunique'),
    cdh1_mutated_patients=('Hugo_Symbol', lambda x: x.notna().sum())
).reset_index()

# Calculate the percentage of CDH1 mutations, handling division by zero for types with no patients
histological_type_summary['percentage_cdh1_mutated'] = histological_type_summary.apply(
    lambda row: (row['cdh1_mutated_patients'] / row['total_patients']) * 100 if row['total_patients'] > 0 else 0,
    axis=1
)

# Sort by percentage and get the top three
top_three_histological_types = histological_type_summary.sort_values(
    by='percentage_cdh1_mutated', ascending=False
).head(3)

print("__RESULT__:")
print(top_three_histological_types.to_json(orient='records'))"""

